import numpy as np

def casimir_effect(temperature):
    return (1 / temperature**2)

def non_equilibrium_thermodynamics(system_complexity, temperature):
    return system_complexity + 0.15 * casimir_effect(temperature)

def test_hypothesis():
    # Generate random system complexity values between 100 and 200
    system_complexities = np.random.uniform(100, 200, size=10)

    for complexity in system_complexities:
        temp = 300  # Critical temperature
        new_complexity = non_equilibrium_thermodynamics(complexity, temp)

        if abs(new_complexity - (complexity + 0.15 * (1 / temp**2))) < 10:  
            print('True')
            return
    print('False')

test_hypothesis()
